        .set({ quantity, updatedAt: new Date() })
        .where(and(eq(inventory.itemId, itemId), eq(inventory.warehouseId, warehouseId)))
        .returning();
      return updated || undefined;
    } else {
      // Create new record
      const [created] = await db
        .insert(inventory)
        .values({ itemId, warehouseId, quantity })
        .returning();
      return created;
    }
  }

